// ─────────────────────────────────────────────────────────────
// CHEMISTRY ENGINE
// ─────────────────────────────────────────────────────────────
function computeChemistry(ingredients) {
  const total = ingredients.reduce((s, i) => s + i.g, 0) || 1;
  const withMol = ingredients.map((ing) => {
    const d = DB[ing.name];
    const wfrac = ing.g / total;
    const molN = wfrac / (d?.MW || 180);
    return { ...ing, wfrac, molN, d };
  });
  const totalMol = withMol.reduce((s, i) => s + i.molN, 0) || 1;
  // First pass: compute raw headspace and OV
  const pass1 = withMol.map((ing) => {
    const { d } = ing;
    if (!d) return { ...ing, xfrac: 0, headspace_ppbv: 0, OV: 0 };
    // d) isUVCB: complex mixture — headspace model doesn't apply
    if (d.isUVCB) return { ...ing, xfrac: 0, headspace_ppbv: 0, OV: 0, intensity: 0, isUVCB: true };
    const xfrac = ing.molN / totalMol;
    // a) dilFactor accounts for pre-diluted products
    const dilFactor = d.dilutionFactor || 1.0;
    // b) use VP * dilFactor for effective partial pressure
    const headspace_ppbv = ((xfrac * d.VP * dilFactor) / 760) * 1e9;
    const OV = headspace_ppbv / d.ODT;
    return { ...ing, xfrac, headspace_ppbv, OV };
  });
  // e) Competitive binding correction: group by scentClass
  const groups = {};
  pass1.forEach((ing) => {
    const sc = ing.d?.scentClass || "Other";
    if (!groups[sc]) groups[sc] = [];
    groups[sc].push(ing);
  });
  // Second pass: apply correction and compute intensity
  return pass1.map((ing) => {
    if (!ing.d) return { ...ing, intensity: 0 };
    const sc = ing.d.scentClass || "Other";
    const group = groups[sc] || [];
    const groupTotalOV = group.reduce((s, m) => s + (m.OV || 0), 0);
    const highOVCount = group.filter((m) => (m.OV || 0) > 1).length;
    let effectiveOV = ing.OV || 0;
    // e) suppress competing members in the same family when ≥2 exceed threshold
    if (highOVCount >= 2 && effectiveOV > 1) {
      effectiveOV = effectiveOV / (1 + (groupTotalOV - effectiveOV) * 0.3);
    }
    // c) OV > 1 threshold: below detection → zero intensity
    const intensity = effectiveOV > 1 ? Math.pow(effectiveOV - 1, ing.d.n) : 0;
    return { ...ing, OV: effectiveOV, intensity };
  });
}

// ─────────────────────────────────────────────────────────────
// INVENTORY ENGINE
// Convert grams needed → closest supplier size to purchase
// ─────────────────────────────────────────────────────────────
function getInventoryPlan(name, gNeeded) {
  const pdata = PRICING[name];
  if (!pdata) return null;
  const d = DB[name];
  const density = d?.densityGmL || 1.0;
  let best = null,
    bestSupplier = null,
    bestQty = Infinity,
    bestPrice = Infinity;
  Object.entries(pdata).forEach(([sup, { url, S }]) => {
    S.forEach(([qty, unit, price]) => {
      const grams = unit === "mL" ? qty * density : qty;
      if (grams >= gNeeded && grams < bestQty) {
        bestQty = grams;
        bestPrice = price;
        bestSupplier = sup;
        best = { qty, unit, price, url, grams, supplier: sup };
      }
    });
    if (!best) {
      // pick largest available
      S.forEach(([qty, unit, price]) => {
        const grams = unit === "mL" ? qty * density : qty;
        if (grams > bestQty || !best) {
          if (!best || grams > bestQty) {
            bestQty = grams;
            bestPrice = price;
            best = { qty, unit, price, url, grams, supplier: sup };
            bestSupplier = sup;
          }
        }
      });
    }
  });
  if (!best) return null;
  return { ...best, remaining: Math.max(0, best.grams - gNeeded) };
}

function totalCost(buildItems) {
  let cost = 0;
  buildItems.forEach((item) => {
    const plan = getInventoryPlan(item.name, item.g);
    if (plan) cost += plan.price;
  });
  return cost;
}
Object.entries(PRICING).forEach(([name, supplierEntries]) => {
  const normalizationEntry = getMaterialNormalizationEntry(name);
  if (!normalizationEntry?.supplierLinks) return;

  Object.entries(supplierEntries || {}).forEach(([supplierName, supplierData]) => {
    const supplierLinkMetadata = normalizationEntry.supplierLinks[supplierName];
    if (!supplierLinkMetadata || !supplierData || typeof supplierData !== "object") {
      return;
    }

    supplierData.linkStatus = supplierLinkMetadata.status || null;
    supplierData.linkNote = supplierLinkMetadata.note || null;
    supplierData.linkedDuplicateOfCatalogName =
      supplierLinkMetadata.duplicateOfCatalogName ||
      normalizationEntry.linkedDuplicateOfCatalogName ||
      null;
  });
});

// ─────────────────────────────────────────────────────────────
// LONGEVITY / SILLAGE / PROJECTION SCORING
// ─────────────────────────────────────────────────────────────
function perfScore(ingredients) {
  const chem = computeChemistry(ingredients);
  const total = ingredients.reduce((s, i) => s + i.g, 0) || 1;
  const bases = chem.filter((i) => i.note === "base" && i.d);
  const mids = chem.filter((i) => i.note === "mid" && i.d);
  const tops = chem.filter((i) => i.note === "top" && i.d);
  // Longevity: low VP bases, high xLogP, fixatives
  const fixPct =
    ingredients
      .filter((i) => PERFORMANCE_FIXATIVE_NAMES.includes(i.name))
      .reduce((s, i) => s + i.g, 0) / total;
  const baseLogP =
    bases.reduce((s, i) => s + i.d.xLogP * i.wfrac, 0) /
    Math.max(
      bases.reduce((s, i) => s + i.wfrac, 0),
      0.01
    );
  // baseLogInvVP: log(1/VP) per base ingredient — ~4.5 for musks, ~2 for light bases
  const baseLogInvVP =
    bases.reduce((s, i) => s + Math.log10(1 / (i.d.VP + 1e-9)) * i.wfrac, 0) /
    Math.max(
      bases.reduce((s, i) => s + i.wfrac, 0),
      0.01
    );
  const longevity = Math.min(
    10,
    (baseLogP / 7) * 3 + (baseLogInvVP / 5) * 4 + fixPct * 6
  );
  // Sillage: physics-based — diffusion rate ∝ √VP / √MW, weighted by OV-intensity and wfrac
  // Cap intensity to prevent ultra-potent molecules (Calone, Ambroxan) from saturating score
  const diffusionScore = chem.reduce((s, i) => {
    if (!i.d || i.OV < 0.1 || !i.d.VP || !i.d.MW) return s;
    const cappedInt = Math.min(i.intensity, 500);
    return s + cappedInt * Math.sqrt(i.d.VP + 1e-8) / Math.sqrt(i.d.MW) * i.wfrac;
  }, 0);
  const sillage = Math.min(10, Math.log10(diffusionScore * 1e4 + 1) * 3.5);
  // Projection: top intensity, high OV tops
  const topInt = tops.reduce((s, i) => s + i.intensity, 0);
  const topPct = tops.reduce((s, i) => s + i.g, 0) / total;
  const projection = Math.min(10, Math.log10(topInt + 1) * 2 + topPct * 8);
  return {
    longevity: Math.max(0, longevity),
    sillage: Math.max(0, sillage),
    projection: Math.max(0, projection),
  };
}

// ─── DB Field Patches ─────────────────────────────────────────────────────────
function genDescriptorTags(name, scentClass, char) {
  const classBase = {
    Marine:   ["marine","aquatic","ozonic","metallic"],
    Musk:     ["musk","clean","powdery","diffusive"],
    Woody:    ["woody","dry","cedar","earthy"],
    Floral:   ["floral","fresh","petals","green"],
    Citrus:   ["citrus","fresh","bright","zesty"],
    Amber:    ["amber","warm","resinous","sweet"],
    Spice:    ["spicy","warm","aromatic","pungent"],
    Green:    ["green","fresh","herbal","leafy"],
    Chypre:   ["chypre","mossy","earthy","oakmoss"],
    Aldehyde: ["aldehyde","powdery","soapy","fatty"],
    Fougere:  ["fougere","aromatic","herbal","coumarin"],
    Gourmand: ["gourmand","sweet","vanilla","edible"],
    Aromatic: ["aromatic","herbal","fresh","clean"],
    Carrier:  ["carrier","neutral","solvent","odorless"],
    Oriental: ["oriental","warm","resinous","balsamic"],
  };
  const stopW = new Set(["from","with","that","this","very","more","some","into","their","also","been","have","over","will","your","but","for","are","the","and","not","was","all","can","has","one","two","key","new","high","low","rich","deep","soft","hard","long","made","both","used","when","than","its","use","per","dry","raw"]);
  const base = classBase[scentClass] || [String(scentClass || "aromatic").toLowerCase()];
  const charWords = String(char || "").toLowerCase().replace(/[^a-z\s-]/g," ").split(/[\s-]+/).filter(w => w.length > 3 && !stopW.has(w));
  const tags = [...new Set([...base, ...charWords])].slice(0, 5);
  return tags.length >= 4 ? tags : [...new Set([...tags, ...base])].slice(0, 4);
}
const _dilOverrides = {
  "Calone 1951":              0.20,
  "Oakmoss Absolute":         0.10,
  "Isobutyl Quinoline":       0.0019,
  "Frangipani Absolute":      0.10,
  "Floralozone\u00ae":        0.50,
  "Floralozone (50%)":        0.50,
  "Undecavertol":             0.25,
  "Undecavertol (25%)":       0.25,
  "Galaxolide 50% IPM":       0.50,
  "Galaxolide 50% DPG":       0.50,
  "Oakmoss Absolute (10%)":   0.10,
  "Frangipani Absolute (10%)":0.10,
  "Osmanthus Absolute (10%)": 0.10,
};
const _uvNames = new Set([
  "Bergamot EO FCF","Lemon EO Italy","Jasmine Sambac Absolute",
  "Ylang-Ylang Extra Oil, Comoros","Ylang Ylang Complete",
  "Himalayan Cedarwood EO","Clearwood\u00ae PRISMA","Clearwood",
  "Oakmoss Absolute (10%)","Frangipani Absolute (10%)","Osmanthus Absolute (10%)",
]);
Object.entries(DB).forEach(([name, d]) => {
  if (_dilOverrides[name] != null) {
    d.dilutionFactor = _dilOverrides[name];
  } else if (d.dilutionFactor == null) {
    if (name.includes("Osmanthus") || name.includes("Frangipani")) d.dilutionFactor = 0.10;
    else if (/10%/.test(name)) d.dilutionFactor = 0.10;
    else if (/20%/.test(name)) d.dilutionFactor = 0.20;
    else if (/50%/.test(name)) d.dilutionFactor = 0.50;
    else if (/25%/.test(name)) d.dilutionFactor = 0.25;
    else d.dilutionFactor = 1.0;
  }
  if (d.isUVCB == null)
    d.isUVCB = d.type === "ABS" || d.type === "EO" || _uvNames.has(name);
  if (d.isIsomerMix == null)
    d.isIsomerMix = name === "Iso E Super" || name === "Iso E Super\u2122";
  if (d.descriptorTags == null)
    d.descriptorTags = genDescriptorTags(name, d.scentClass, d.char);
});
