        allIngs[ing.name].formulas[formulaLabel] =
          (allIngs[ing.name].formulas[formulaLabel] || 0) + ing.g;
        allIngs[ing.name].totalNeeded[formulaLabel] =
          (allIngs[ing.name].totalNeeded[formulaLabel] || 0) + n;
